import sailpoint.object.Identity;
Identity launcher = context.getObjectByName(Identity.class, wfcontext.getLauncher());
return (launcher != null) ? launcher.getName() : "spadmin";

import sailpoint.api.Provisioner;
import sailpoint.object.ProvisioningPlan;
import sailpoint.object.ProvisioningProject;

Provisioner provisioner = new Provisioner(context);
ProvisioningProject proj = provisioner.compile(plan, null, null);
workflow.put("project", proj);

import sailpoint.api.Provisioner;
import sailpoint.object.ProvisioningProject;
import sailpoint.object.ProvisioningResult;

Provisioner provisioner = new Provisioner(context);
provisioner.execute(project);

// Check for errors in the project
if (project.getErrors() != null && !project.getErrors().isEmpty()) {
    workflow.put("provisioningErrors", project.getErrors().toString());
    workflow.put("workItemStatus", "Failed");
} else {
    workflow.put("workItemStatus", "Success");
}

