import sailpoint.object.Application;

/**
 * Validates required inputs and verifies the application exists.
 * Returns null on success, or an error string on failure.
 */
public String validateInputs() {
    if (appName == null || appName.trim().equals("")) {
        return "appName is required.";
    }
    if (groupName == null || groupName.trim().equals("")) {
        return "groupName is required.";
    }
    if (groupBaseDN == null || groupBaseDN.trim().equals("")) {
        return "groupBaseDN is required.";
    }

    Application app = context.getObjectByName(Application.class, appName);
    if (app == null) {
        return "Application not found in IIQ: " + appName;
    }

    return null; // no errors
}

/**
 * Builds a ProvisioningPlan with an ObjectRequest to create the AD group.
 * Uses AccountRequest type GROUP to create the group object on the connector.
 */
public sailpoint.object.ProvisioningPlan buildProvisioningPlan() {
    import sailpoint.object.ProvisioningPlan;
    import sailpoint.object.ProvisioningPlan.AccountRequest;
    import sailpoint.object.ProvisioningPlan.AttributeRequest;
    import sailpoint.object.ProvisioningPlan.ObjectRequest;
    import sailpoint.object.ProvisioningPlan.Operation;
    import sailpoint.object.Application;

    ProvisioningPlan plan = new ProvisioningPlan();

    // --- ObjectRequest: create the AD group ---
    ObjectRequest objReq = new ObjectRequest();
    objReq.setApplication(appName);
    objReq.setType("group");                         // IIQ schema type for AD groups
    objReq.setOp(ObjectRequest.Operation.Create);
    objReq.setNativeIdentity(groupName);             // CN or sAMAccountName

    // Set the group distinguished name / base OU
    objReq.add(new AttributeRequest("distinguishedName",
        Operation.Set,
        "CN=" + groupName + "," + groupBaseDN));

    // cn
    objReq.add(new AttributeRequest("cn",
        Operation.Set,
        groupName));

    // sAMAccountName
    objReq.add(new AttributeRequest("sAMAccountName",
        Operation.Set,
        groupName));

    // Group description (optional)
    if (groupDescription != null && !groupDescription.trim().equals("")) {
        objReq.add(new AttributeRequest("description",
            Operation.Set,
            groupDescription));
    }

    // FIS Resource Owners â stored in extensionAttribute1 (adjust attribute name as needed)
    if (fisResourceOwners != null && !fisResourceOwners.trim().equals("")) {
        objReq.add(new AttributeRequest("extensionAttribute1",
            Operation.Set,
            fisResourceOwners));
    }

    // groupType: -2147483646 = Global Security Group in AD
    objReq.add(new AttributeRequest("groupType",
        Operation.Set,
        "-2147483646"));

    plan.add(objReq);

    // Set the requester for audit trail
    plan.setRequesters(java.util.Arrays.asList(
        new sailpoint.object.Identity.NameRef(launcher)));

    return plan;
}
